#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c<=(b);--c)
#define grep(a,b,c) for(int c=a.head[b];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a)) 
using namespace std;
const int N=305,M=13005,INF=0x3f3f3f3f;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
struct Graph{int head[N],des[M],nxt[M],cap[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;cap[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}}a;
int dep[N],s,t,que[N],H,T,n,m;

inline bool bfs()
{
	Clear(dep);dep[que[H=T=1]=s]=1;while(H<=T)
	{int u=que[H++];grep(a,u,i){int v=a.des[i];if(a.cap[i]&&!dep[v])dep[v]=dep[u]+1,que[++T]=v;}}return dep[t];
}
int dfs(int u,int in)
{
	if(u==t)return in;int out=0;grep(a,u,i)
	{
		int v=a.des[i];if(a.cap[i]&&dep[v]==dep[u]+1)
			{int tmp=dfs(v,min(in,a.cap[i]));a.cap[i]-=tmp;a.cap[i^1]+=tmp;in-=tmp;out+=tmp;}if(!in)break;
	}if(!out)dep[u]=0;return out;
}
inline int dinic(int u,int v){s=u;t=v;int res=0;while(bfs())res+=dfs(s,INF);return res;}
void print(int u){if(u==2*n+1)return;printf("%d ",u);grep(a,u,i){if(!a.cap[i]&&a.des[i]!=2*n+1){print(a.des[i]-n);break;}}}
int main()
{
	n=read();m=read();a.cnt=1;rep(1,m,i){int x=read(),y=read();a.ins(x,y+n,1);a.ins(y+n,x,0);}
	rep(1,n,i)a.ins(n*2+1,i,1),a.ins(i,n*2+1,0);rep(n+1,2*n,i)a.ins(i,n*2+2,1),a.ins(n*2+2,i,0);
	int res=dinic(2*n+1,2*n+2);grep(a,t,i){if(!a.cap[i])print(a.des[i]-n),puts("");} printf("%d",n-res);
}
